sections.matlabComparison:
% MATLAB equivalent for normalized cross-correlation
h = conj(flipud(preamble(:)));
corr = filter(h, 1, rx_signal);
rx_energy = filter(ones(64,1), 1, abs(rx_signal).^2);
metric = abs(corr).^2 ./ (rx_energy * sum(abs(preamble).^2));
[val, idx] = max(metric);
detected_offset = idx - 64;
